    public static func extractComponents(
        fromUnescapedPayload payload: String,
        groupRootID: StatusComponentID
    ) -> [StatusComponent] {
        // Strategy: walk every `"id":"<ULID>"` occurrence, then look inside a
        // bounded window around the match for the sibling `"name"` and
        // `"group_id"` fields. This is more robust than a single-shot regex
        // because the RSC serializer's field ordering varies and we don't
        // want to maintain N patterns for N permutations.
        //
        // ULIDs are 26 chars of Crockford base32 (excluding I, L, O, U). The
        // anchor on that shape keeps us from grabbing unrelated `id` fields.
        let ulid = #"[0-9A-HJKMNP-TV-Z]{26}"#
        let nsPayload = payload as NSString
        let totalLength = nsPayload.length

        guard let idAnchor = try? NSRegularExpression(
            pattern: #"\"id\"\s*:\s*\"(\#(ulid))\""#,
            options: []
        ) else { return [] }

        // Sibling fields live inside the same JSON object. RSC objects we
        // care about are small (<400 chars in practice); a window large
        // enough to span every observed component but small enough to avoid
        // bleeding into the next object.
        let windowChars = 400

        var seenIDs = Set<String>()
        var matches: [StatusComponent] = []
        let range = NSRange(location: 0, length: totalLength)
        idAnchor.enumerateMatches(in: payload, options: [], range: range) { match, _, _ in
            guard let match, match.numberOfRanges == 2 else { return }
            let idRange = match.range(at: 1)
            let idValue = nsPayload.substring(with: idRange)

            let windowStart = max(0, match.range.location - windowChars)
            let windowEnd = min(totalLength, match.range.location + match.range.length + windowChars)
            let windowRange = NSRange(location: windowStart, length: windowEnd - windowStart)
            let window = nsPayload.substring(with: windowRange)

            guard let name = firstStringField(named: "name", in: window),
                  let groupID = firstStringField(named: "group_id", in: window) else {
                return
            }
            guard groupID == groupRootID.rawValue else { return }
            guard seenIDs.insert(idValue).inserted else { return }
            matches.append(StatusComponent(
                id: StatusComponentID(rawValue: idValue),
                name: name,
                groupID: StatusComponentID(rawValue: groupID)
            ))
        }
        return matches
    }

    private static func firstStringField(named field: String, in text: String) -> String? {
        let pattern = "\"\(field)\"\\s*:\\s*\"([^\"\\\\]{1,200})\""
        guard let regex = try? NSRegularExpression(pattern: pattern, options: []) else {
            return nil
        }
        let ns = text as NSString
        let range = NSRange(location: 0, length: ns.length)
        guard let match = regex.firstMatch(in: text, options: [], range: range),
              match.numberOfRanges == 2 else { return nil }
        return ns.substring(with: match.range(at: 1))
    }
}

