    public static func extractComponents(
        fromUnescapedPayload payload: String,
        groupRootID: StatusComponentID
    ) -> [StatusComponent] {
        // Strategy: collect every `"id"`, `"name"`, and `"group_id"` field
        // occurrence with its position. Then for each `"id"` anchor, pair it
        // with the nearest `"name"` and `"group_id"` whose positions are not
        // separated from the id by another `"id"` anchor — that proxies
        // "same JSON object" without needing a true JSON parser (the RSC
        // stream is not valid JSON in isolation).
        //
        // ULIDs are 26 chars of Crockford base32 (excluding I, L, O, U).
        let ulid = #"[0-9A-HJKMNP-TV-Z]{26}"#

        let idMatches = matches(
            pattern: #"\"id\"\s*:\s*\"(\#(ulid))\""#,
            in: payload
        )
        let nameMatches = matches(
            pattern: #"\"name\"\s*:\s*\"([^\"\\]{1,200})\""#,
            in: payload
        )
        let groupMatches = matches(
            pattern: #"\"group_id\"\s*:\s*\"(\#(ulid))\""#,
            in: payload
        )

        var seenIDs = Set<String>()
        var components: [StatusComponent] = []
        for (idx, anchor) in idMatches.enumerated() {
            let previousIDPosition = idx == 0 ? 0 : idMatches[idx - 1].position
            let nextIDPosition = idx + 1 < idMatches.count ? idMatches[idx + 1].position : Int.max

            // "Same object" approximation: a sibling field must lie strictly
            // between the previous id anchor and the next id anchor.
            let lowerBound = previousIDPosition
            let upperBound = nextIDPosition

            guard let name = nearest(
                to: anchor.position, in: nameMatches,
                lowerBound: lowerBound, upperBound: upperBound
            ) else { continue }
            guard let groupID = nearest(
                to: anchor.position, in: groupMatches,
                lowerBound: lowerBound, upperBound: upperBound
            ) else { continue }
            guard groupID.captured == groupRootID.rawValue else { continue }
            guard seenIDs.insert(anchor.captured).inserted else { continue }
            components.append(StatusComponent(
                id: StatusComponentID(rawValue: anchor.captured),
                name: name.captured,
                groupID: StatusComponentID(rawValue: groupID.captured)
            ))
        }
        return components
    }

    private struct FieldMatch {
        let position: Int
        let captured: String
    }

    private static func matches(pattern: String, in text: String) -> [FieldMatch] {
        guard let regex = try? NSRegularExpression(pattern: pattern, options: []) else {
            return []
        }
        let ns = text as NSString
        let range = NSRange(location: 0, length: ns.length)
        var results: [FieldMatch] = []
        regex.enumerateMatches(in: text, options: [], range: range) { match, _, _ in
            guard let match, match.numberOfRanges == 2 else { return }
            let captured = ns.substring(with: match.range(at: 1))
            results.append(FieldMatch(position: match.range.location, captured: captured))
        }
        return results
    }

    private static func nearest(
        to anchor: Int,
        in candidates: [FieldMatch],
        lowerBound: Int,
        upperBound: Int
    ) -> FieldMatch? {
        var best: FieldMatch?
        var bestDistance = Int.max
        for candidate in candidates where candidate.position > lowerBound && candidate.position < upperBound {
            let distance = abs(candidate.position - anchor)
            if distance < bestDistance {
                bestDistance = distance
                best = candidate
            }
        }
        return best
    }
}

