    public static func extractComponents(
        fromUnescapedPayload payload: String,
        groupRootID: StatusComponentID
    ) -> [StatusComponent] {
        // Strategy: walk the payload and slice it at JSON object boundaries
        // (depth-0 `{...}`). String literals are skipped so `}` characters
        // inside a string don't pop the brace stack. Each slice is then
        // independently scanned for the `id`, `name`, and `group_id`
        // string fields — siblings cannot leak across object boundaries
        // even when objects appear back-to-back.
        var components: [StatusComponent] = []
        var seenIDs = Set<String>()
        for slice in enumerateTopLevelObjects(in: payload) {
            guard let component = extractComponent(fromSingleObject: slice, groupRootID: groupRootID) else {
                continue
            }
            if seenIDs.insert(component.id.rawValue).inserted {
                components.append(component)
            }
        }
        return components
    }

    private static func enumerateTopLevelObjects(in payload: String) -> [String] {
        var depth = 0
        var inString = false
        var escaped = false
        var sliceStart: String.Index?
        var slices: [String] = []

        var index = payload.startIndex
        while index < payload.endIndex {
            let ch = payload[index]
            if inString {
                if escaped {
                    escaped = false
                } else if ch == "\\" {
                    escaped = true
                } else if ch == "\"" {
                    inString = false
                }
            } else {
                switch ch {
                case "\"":
                    inString = true
                case "{":
                    if depth == 0 {
                        sliceStart = index
                    }
                    depth += 1
                case "}":
                    depth -= 1
                    if depth == 0, let start = sliceStart {
                        let endInclusive = payload.index(after: index)
                        slices.append(String(payload[start..<endInclusive]))
                        sliceStart = nil
                    }
                default:
                    break
                }
            }
            index = payload.index(after: index)
        }
        return slices
    }

