            guard let name = nameByID[idx], let groupID = groupByID[idx] else { continue }
            guard groupID == groupRootID.rawValue else { continue }
            guard seenIDs.insert(anchor.captured).inserted else { continue }
            components.append(StatusComponent(
                id: StatusComponentID(rawValue: anchor.captured),
                name: name,
                groupID: StatusComponentID(rawValue: groupID)
            ))
        }
        return components
    }

    private struct FieldMatch {
        let position: Int
        let captured: String
    }

    private static func matches(pattern: String, in text: String) -> [FieldMatch] {
        guard let regex = try? NSRegularExpression(pattern: pattern, options: []) else {
            return []
        }
        let ns = text as NSString
        let range = NSRange(location: 0, length: ns.length)
        var results: [FieldMatch] = []
        regex.enumerateMatches(in: text, options: [], range: range) { match, _, _ in
            guard let match, match.numberOfRanges == 2 else { return }
            let captured = ns.substring(with: match.range(at: 1))
            results.append(FieldMatch(position: match.range.location, captured: captured))
        }
        return results
    }

    private static func assignToNearestAnchor(
        siblings: [FieldMatch],
        anchors: [FieldMatch]
    ) -> [Int: String] {
        var result: [Int: String] = [:]
        for sibling in siblings {
            var bestIndex: Int?
            var bestDistance = Int.max
            for (idx, anchor) in anchors.enumerated() {
                let distance = abs(sibling.position - anchor.position)
                if distance < bestDistance {
                    bestDistance = distance
                    bestIndex = idx
                }
            }
            // First sibling that picks an anchor wins; later siblings
            // claiming the same anchor are ignored. This makes the parser
            // deterministic when an upstream object happens to carry
            // multiple `name` fields (e.g. nested objects).
            if let bestIndex, result[bestIndex] == nil {
                result[bestIndex] = sibling.captured
            }
        }
        return result
    }
}

