        while index >= payload.startIndex {
            let ch = payload[index]
            if ch == "}" {
                depth += 1
            } else if ch == "{" {
                if depth == 0 {
                    openIndex = index
                    break
                }
                depth -= 1
            }
            if index == payload.startIndex { break }
            index = payload.index(before: index)
        }
        guard let openIndex else { return nil }

        depth = 0
        var forward = needleRange.upperBound
