@Suite("IncidentIOComponentsDiscovery — RSC parser")
struct IncidentIOComponentsDiscoveryTests {
    private let codexGroupRootID: StatusComponentID = "01KMKF9EBTCD8BN9PG8DJZXRSQ"

    @Test("extracts Codex child components from a plain JSON payload")
    func extractsFromUnescapedPayload() {
        let payload = """
        garbage prefix … {
          "id": "01JVCV8YSWZFRSM1G5CVP253SK",
          "name": "Codex Web",
          "group_id": "01KMKF9EBTCD8BN9PG8DJZXRSQ"
        } … intermediate garbage … {
          "id": "01KMP3KP5MGE23B80K1EK4S8PV",
          "name": "Codex API",
          "group_id": "01KMKF9EBTCD8BN9PG8DJZXRSQ"
        } … and one unrelated component … {
          "id": "01KRG0AZKH41DV4D9SNJSXM33Q",
          "name": "Audio",
          "group_id": "01ZZZZZZZZZZZZZZZZZZZZZZZZ"
        }
        """
        let components = IncidentIOPageComponentsDiscovery.extractComponents(
            fromUnescapedPayload: payload,
            groupRootID: codexGroupRootID
        )
        #expect(components.count == 2)
        #expect(components.contains { $0.name == "Codex Web" })
        #expect(components.contains { $0.name == "Codex API" })
        #expect(components.allSatisfy { $0.groupID == codexGroupRootID })
    }

    @Test("supports both field orderings (id,group_id,name and id,name,group_id)")
    func supportsAlternateOrdering() {
        let payload = """
        {"id":"01AAAAAAAAAAAAAAAAAAAAAAAA","group_id":"01KMKF9EBTCD8BN9PG8DJZXRSQ","name":"App"}
        {"id":"01BBBBBBBBBBBBBBBBBBBBBBBB","name":"CLI","group_id":"01KMKF9EBTCD8BN9PG8DJZXRSQ"}
        """
        let components = IncidentIOPageComponentsDiscovery.extractComponents(
            fromUnescapedPayload: payload,
            groupRootID: codexGroupRootID
        )
        #expect(components.count == 2)
        #expect(components.contains { $0.name == "App" })
        #expect(components.contains { $0.name == "CLI" })
    }

    @Test("unescapes \\\" inside an HTML script-tag style payload")
    func unescapesScriptPayload() {
        // Simulates the RSC payload as it appears inside a JS string literal,
        // where every `"` is escaped to `\\"`.
        let html = #"""
        <script>self.__next_f.push([1,"a:[{\"id\":\"01JVCV8YSWZFRSM1G5CVP253SK\",\"name\":\"Codex Web\",\"group_id\":\"01KMKF9EBTCD8BN9PG8DJZXRSQ\"}]"])</script>
        """#
        let components = IncidentIOPageComponentsDiscovery.extractComponents(
            fromHTML: html,
            groupRootID: codexGroupRootID
        )
        #expect(components.count == 1)
        #expect(components[0].id.rawValue == "01JVCV8YSWZFRSM1G5CVP253SK")
        #expect(components[0].name == "Codex Web")
    }

    @Test("returns empty when no component matches the group root (tampered fixture)")
    func tamperedFixtureReturnsEmpty() {
        let payload = """
        {"id":"01XXXXXXXXXXXXXXXXXXXXXXXX","name":"Unrelated","group_id":"01YYYYYYYYYYYYYYYYYYYYYYYY"}
        """
        let components = IncidentIOPageComponentsDiscovery.extractComponents(
            fromUnescapedPayload: payload,
            groupRootID: codexGroupRootID
        )
        #expect(components.isEmpty)
    }

    @Test("deduplicates components that match both ordering patterns")
    func deduplicatesAcrossPatterns() {
        // A single object should not be counted twice even if both regex
        // patterns happen to match it (they don't today — the field order
        // is exclusive — but a future relaxation must not double-count).
        let payload = """
        {"id":"01AAAAAAAAAAAAAAAAAAAAAAAA","name":"Codex Web","group_id":"01KMKF9EBTCD8BN9PG8DJZXRSQ"}
        """
        let components = IncidentIOPageComponentsDiscovery.extractComponents(
            fromUnescapedPayload: payload,
            groupRootID: codexGroupRootID
        )
        #expect(components.count == 1)
    }
}

